Source code in <code>trainer_tools/trainer.py</code> <pre><code>def get_hook(self, cls: Type[T], default=RAISE) -&gt; T:
    for h in self.hooks:
        if isinstance(h, cls):
            return h
    if default is not RAISE:
        return default
    raise KeyError(f"Hook {cls} not found")
